from agno.memory import ConversationMemory

def detect_memory_drift(session_memory: ConversationMemory, current_message):
    referenced_interactions = session_memory.get_references(current_message)

    for ref in referenced_interactions:
        if ref.timestamp not in session_memory.history:
            return True, f'Fabricated memory reference: {ref.content}'

    return False, 'Memory consistent'

from pydantic import ValidationError
from agno.structured import StructuredAgent

def detect_schema_drift(agent: StructuredAgent, response):
    try:
        validated = agent.schema_model(**response.dict())
        return False, 'Schema valid'
    except ValidationError as e:
        missing_fields = [err['loc'] for err in e.errors() if err['type'] == 'value_error.missing']
        return True, f'Schema drift: missing {missing_fields}'

