from agno.agent import Agent
from agno.tools.vision import GPT4Vision

def fix_image_drift(agent: Agent):
    vision_tool = GPT4Vision()

    @agent.tool()
    def validate_visual_facts(self, image_desc: str, image_url: str) -> str:
        """Validate if description matches actual image content"""
        facts = vision_tool.analyze(image_url)
        if not any(fact in image_desc for fact in facts):
            return f'CORRECTION: Image contains {facts}, not {image_desc}'
        return 'Description accurate'

from agno.memory import ConversationMemory

class DriftProofMemory(ConversationMemory):
    def recall(self, query: str):
        memories = super().recall(query)
        verified = []
        for mem in memories:
            if self._verify_timestamp(mem):
                verified.append(mem)
        return verified

    def _verify_timestamp(self, mem):
        return mem.timestamp in self.history_timestamps

from pydantic import BaseModel, Field
from typing import Any

def recover_schema_drift(model: BaseModel, partial_data: dict) -> dict:
    data = partial_data.copy()

    for field_name, field in model.model_fields.items():
        if field_name not in data:
            if field.default is not None:
                data[field_name] = field.default
            elif hasattr(field, 'default_factory'):
                data[field_name] = field.default_factory()

    return model(**data).model_dump()
